### Configure XAxis and YAxis Components with Customization in Recharts

Source: https://context7.com/recharts/recharts/llms.txt

This example demonstrates how to configure XAxis and YAxis components in Recharts. It includes custom tick formatting, rotation, and a custom tick component for the X-axis, as well as setting custom domains, ticks, formatters, and labels for the Y-axis, including a secondary Y-axis.

```jsx
import React from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const data = [
  { date: '2024-01-01', value: 4000, category: 'A' },
  { date: '2024-02-01', value: 3000, category: 'B' },
  { date: '2024-03-01', value: 2000, category: 'C' },
  { date: '2024-04-01', value: 2780, category: 'D' },
  { date: '2024-05-01', value: 1890, category: 'E' },
];

const CustomTick = ({ x, y, payload }) => {
  return (
    <g transform={`translate(${x},${y})`}>
      <text
        x={0}
        y={0}
        dy={16}
        textAnchor="end"
        fill="#666"
        transform="rotate(-35)"
      >
        {payload.value}
      </text>
    </g>
  );
};

function AxisConfigurationExample() {
  return (
    <ResponsiveContainer width="100%" height={400}>
      <LineChart data={data} margin={{ top: 5, right: 30, left: 20, bottom: 60 }}>
        <CartesianGrid strokeDasharray="3 3" />

        {/* Custom X-Axis with formatting */}
        <XAxis
          dataKey="date"
          angle={-45}
          textAnchor="end"
          height={80}
          tick={CustomTick}
          tickFormatter={(value) => new Date(value).toLocaleDateString()}
        />

        {/* Y-Axis with custom domain and ticks */}
        <YAxis
          domain={[0, 5000]}
          ticks={[0, 1000, 2000, 3000, 4000, 5000]}
          tickFormatter={(value) => `$${value}`}
          label={{ value: 'Revenue', angle: -90, position: 'insideLeft' }}
        />

        {/* Secondary Y-Axis */}
        <YAxis
          yAxisId="right"
          orientation="right"
          stroke="#82ca9d"
          label={{ value: 'Count', angle: 90, position: 'insideRight' }}
        />

        <Tooltip />
        <Line type="monotone" dataKey="value" stroke="#8884d8" yAxisId="left" />
      </LineChart>
    </ResponsiveContainer>
  );
}

export default AxisConfigurationExample;
```

